COMPLEMENT_DFA(M):
 // M = (Q, Σ, δ, s, F) - must be DFA

 // Convert NFA to DFA if needed first
 M_DFA ← CONVERT_TO_DFA(M)

 // Swap accepting and non-accepting states
 F' ← Q - M_DFA.F // All states NOT in F

 RETURN DFA(M_DFA.Q, Σ, M_DFA.δ, M_DFA.s, F')

KLEENE_STAR(N):
 // N = (Q, Σ, δ, s, F) for language L

 Q' ← Q ∪ {s_new} // Add new start state
 s' ← s_new
 F' ← F ∪ {s_new} // New start is also accepting
 δ' ← δ

 // Add epsilon transitions from old accepting states back to old start
 FOR each state f ∈ F:
 δ'(f, ε) ← δ'(f, ε) ∪ {s}

 // Add epsilon from new start to old start (for empty string)
 δ'(s_new, ε) ← {s}

 RETURN NFA(Q', Σ, δ', s', F')
